    20→const DEFAULT_PROFILE_LAYOUT = {
    21→    version: 1,
    22→    preset: 'classic',
    23→    spacing: 'md',
    24→    radius: 'lg',
    25→    sections: [
    26→        {id: 'stats', visible: true, size: 'md'},
    27→        {id: 'bio', visible: true, size: 'md'},
    28→        {id: 'joined_date', visible: true, size: 'md'},
    29→    ]
    30→};
    31→const PROFILE_SECTION_IDS = ['stats', 'bio', 'joined_date'];
    32→const PROFILE_SECTION_SIZES = ['sm', 'md', 'lg'];
    33→const PROFILE_WIDGET_TYPES = ['note', 'photo_note'];
    34→
    35→const normalizeProfileLayout = (layout) => {
    36→    const incomingSections = Array.isArray(layout?.sections) ? layout.sections : [];
    37→    const normalizedSections = [];
    38→
    39→    incomingSections.forEach((section) => {
    40→        if(!PROFILE_SECTION_IDS.includes(section?.id)){
    41→            return;
    42→        }
    43→        if(normalizedSections.find((item) => item.id === section.id)){
    44→            return;
    45→        }
    46→
    47→        normalizedSections.push({
    48→            id: section.id,
    49→            visible: section.visible !== false,
    50→            size: PROFILE_SECTION_SIZES.includes(section?.size) ? section.size : 'md'
    51→        });
    52→    });
    53→
    54→    PROFILE_SECTION_IDS.forEach((sectionId) => {
    55→        if(normalizedSections.find((section) => section.id === sectionId)){
    56→            return;
    57→        }
    58→
    59→        const defaultSection = DEFAULT_PROFILE_LAYOUT.sections.find((section) => section.id === sectionId);
    60→        normalizedSections.push({...defaultSection});
    61→    });
    62→
    63→    return {
    64→        version: layout?.version || DEFAULT_PROFILE_LAYOUT.version,
    65→        preset: layout?.preset || DEFAULT_PROFILE_LAYOUT.preset,
    66→        spacing: layout?.spacing || DEFAULT_PROFILE_LAYOUT.spacing,
    67→        radius: layout?.radius || DEFAULT_PROFILE_LAYOUT.radius,
    68→        sections: normalizedSections,
    69→        widgets: (Array.isArray(layout?.widgets) ? layout.widgets : [])
    70→            .filter((widget) => widget && typeof widget === 'object')
    71→            .map((widget) => ({
    72→                id: widget.id || `widget_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    73→                type: PROFILE_WIDGET_TYPES.includes(widget.type) ? widget.type : 'note',
    74→                size: PROFILE_SECTION_SIZES.includes(widget.size) ? widget.size : 'md',
    75→                title: typeof widget.title === 'string' ? widget.title : '',
    76→                note: typeof widget.note === 'string' ? widget.note : '',
    77→                image_url: typeof widget.image_url === 'string' ? widget.image_url : '',
    78→                image_width: Number.isFinite(widget?.image_width) ? Math.max(60, widget.image_width) : null,
    79→                image_height: Number.isFinite(widget?.image_height) ? Math.max(40, widget.image_height) : null,
    80→                bg_color: typeof widget.bg_color === 'string' ? widget.bg_color : null,
    81→                blocks: Array.isArray(widget.blocks) ? widget.blocks
    82→                    .filter((b) => b && typeof b === 'object')
    83→                    .map((block) => ({
    84→                        id: block.id || `block_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    85→                        type: ['text', 'image'].includes(block.type) ? block.type : 'text',
    86→                        content: typeof block.content === 'string' ? block.content : '',
    87→                        title: typeof block.title === 'string' ? block.title : '',
    88→                        note: typeof block.note === 'string' ? block.note : '',
    89→                        image_url: typeof block.image_url === 'string' ? block.image_url : '',
    90→                        bg_color: typeof block.bg_color === 'string' ? block.bg_color : null,
    91→                        x: Number.isFinite(block.x) ? Math.max(0, block.x) : 0,
    92→                        y: Number.isFinite(block.y) ? Math.max(0, block.y) : 0,
    93→                        width: Number.isFinite(block.width) ? Math.max(40, block.width) : 160,
