   130→
   131→    normalized.sections = normalizedSections;
   132→
   133→    const incomingWidgets = Array.isArray(layout?.widgets) ? layout.widgets : [];
   134→    normalized.widgets = incomingWidgets
   135→        .filter((widget) => widget && typeof widget === 'object')
