     1→import supabase from "./supabase.js"
     2→
     3→export const getUserDataService = async(userId) =>{
     4→    if(!userId){
     5→        throw {status: 400, message: 'userid is undefined'}
     6→    }
     7→    const userDataPromise = supabase
     8→    .from('users')
     9→    .select('*')
    10→    .eq('id', userId)
    11→
    12→    const followerCountPromise = supabase
    13→    .from('follows')
    14→    .select('*', {count: 'exact', head: true})
    15→    .eq('following_id', userId)
    16→
    17→    const followingCountPromise = supabase
    18→    .from('follows')
    19→    .select('*', {count: 'exact', head: true})
    20→    .eq('follower_id', userId)
    21→
    22→    const [userDataResult, followerCountResult, followingCountResult] = await Promise.all([
    23→        userDataPromise, followerCountPromise, followingCountPromise
    24→    ])
    25→
    26→    const {data: userData, error: errorUserData} = userDataResult;
    27→    const {count: followerCount, error: errorFollowerCount} = followerCountResult;
    28→    const {count: followingCount, error: errorFollowingCount} = followingCountResult;
    29→
    30→    if(errorUserData || errorFollowerCount || errorFollowingCount){
    31→        console.error('supabase error while fetching user data:', errorUserData || errorFollowerCount || errorFollowingCount)
    32→        throw {status: 400, message: 'supabase error while fetching user data'}
    33→    }
    34→    const data = {userData: userData, followerCount: followerCount, followingCount: followingCount}
    35→    return data;
    36→}

